To develop a Checkers game using Python, we'll need to create several classes and methods that handle different aspects of the game. Below is an outline of the steps and code snippets required:

1. **Define the `Piece` class**: Represents each piece on the board (either red or white).
2. **Define the `Board` class**: Manages the state of the board, including pieces and their positions.
3. **Define the `Game` class**: Handles the game logic, including turn management, move validation, captures, and kings.
4. **Define utility functions for move parsing and printing**.

Let's start by implementing these classes step-by-step.

### Step 1: Define the `Piece` Class

```python
class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def make_king(self):
        self.king = True

    def __str__(self):
        if self.color == "red":
            return 'R' if not self.king else 'r'
        else:
            return 'B' if not self.king else 'b'

    @staticmethod
    def from_char(char):
        if char in ['R', 'r']:
            return Piece("red")
        elif char in ['B', 'b']:
            return Piece("white")
        return None
```

### Step 2: Define the `Board` Class

```python
class Board:
    def __init__(self):
        self.board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        for i in range(3):
            for j in range((i % 2) + 1, 8, 2):
                self.board[i][j] = Piece("red")
        for i in range(5, 8):
            for j in range((i % 2) + 1, 8, 2):
                self.board[i][j] = Piece("white")

    def print_board(self):
        for row in self.board:
            print(" ".join(str(piece) if piece else '.' for piece in row))

    def move_piece(self, start, end):
        piece = self.board[start[0]][start[1]]
        self.board[start[0]][start[1]] = None
        self.board[end[0]][end[1]] = piece

    def is_valid_move(self, start, end):
        piece = self.board[start[0]][start[1]]
        if not piece:
            return False

        x_dir = 1 if piece.color == "red" else -1
        if abs(end[0] - start[0]) != 1 or abs(end[1] - start[1]) not in [1, 2]:
            return False

        if end[1] < 0 or end[1] >= 8:
            return False

        destination = self.board[end[0]][end[1]]
        if destination is not None:
            return False

        # Check for capture
        if abs(end[1] - start[1]) == 2 and self.is_capture(start, end):
            mid_x = (start[0] + end[0]) // 2
            mid_y = (start[1] + end[1]) // 2
            captured_piece = self.board[mid_x][mid_y]
            if not captured_piece or captured_piece.color == piece.color:
                return False

        # Check for valid non-capture move
        if abs(end[1] - start[1]) == 1 and piece.king:
            mid_x = (start[0] + end[0]) // 2
            mid_y = (start[1] + end[1]) // 2
            if self.board[mid_x][mid_y]:
                return False

        return True

    def is_capture(self, start, end):
        x_dir = 1 if piece.color == "red" else -1
        mid_x = (start[0] + end[0]) // 2
        mid_y = (start[1] + end[1]) // 2
        return self.board[mid_x][mid_y] is not None and self.board[mid_x][mid_y].color != piece.color
```

### Step 3: Define the `Game` Class

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = "red"

    def print_board(self):
        self.board.print_board()

    def switch_turn(self):
        self.current_player = "white" if self.current_player == "red" else "red"

    def make_move(self, start, end):
        if not self.board.is_valid_move(start, end):
            raise ValueError("Invalid move")

        self.board.move_piece(start, end)
        piece = self.board.board[end[0]][end[1]]
        if abs(end[0] - start[0]) == 2:
            mid_x = (start[0] + end[0]) // 2
            mid_y = (start[1] + end[1]) // 2
            self.board.board[mid_x][mid_y] = None

        if end[0] in [0, 7]:
            piece.make_king()

        self.switch_turn()
```

### Step 4: Utility Functions for Move Parsing and Printing

```python
def parse_move(move_str):
    start = (ord(move_str[0]) - ord('a'), int(move_str[1]) - 1)
    end = (ord(move_str[2]) - ord('a'), int(move_str[3]) - 1)
    return start, end

def main():
    game = Game()
    while True:
        game.print_board()
        move_str = input(f"{game.current_player}'s turn. Enter your move (e.g., 'a1b2'): ")
        if move_str.lower() == "quit":
            break
        try:
            start, end = parse_move(move_str)
            game.make_move(start, end)
        except ValueError as e:
            print(e)

if __name__ == "__main__":
    main()
```

